  "inlineSchema": "// Influence Factory - Multi-tenant Database Schema\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================================\n// MULTI-TENANT CORE\n// ============================================================================\n\nmodel Tenant {\n  id                String   @id @default(uuid())\n  name              String\n  email             String   @unique\n  subscriptionTier  String   @default(\"free\") // free, starter, pro, enterprise\n  status            String   @default(\"active\")\n  apiQuotaMonthly   Int      @default(10000)\n  apiUsageThisMonth Int      @default(0)\n  createdAt         DateTime @default(now())\n  updatedAt         DateTime @updatedAt\n\n  // Relations\n  users          User[]\n  projects       Project[]\n  wordPressSites WordPressSite[]\n  posts          Post[]\n  jobs           Job[]\n  patterns       PersonalPattern[]\n\n  @@index([email])\n  @@index([status])\n}\n\nmodel User {\n  id          String    @id @default(uuid())\n  tenantId    String\n  email       String\n  name        String?\n  role        String    @default(\"member\") // owner, admin, member\n  lastLoginAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@unique([tenantId, email])\n  @@index([tenantId])\n  @@index([email])\n}\n\n// ============================================================================\n// PROJECTS & CONFIGURATION\n// ============================================================================\n\nmodel Project {\n  id                String   @id @default(uuid())\n  tenantId          String\n  name              String\n  description       String?\n  authorityStrategy String   @default(\"data-driven\")\n  status            String   @default(\"active\")\n  createdAt         DateTime @default(now())\n  updatedAt         DateTime @updatedAt\n\n  tenant         Tenant          @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  posts          Post[]\n  wordPressSites WordPressSite[]\n\n  @@index([tenantId])\n}\n\nmodel WordPressSite {\n  id          String    @id @default(uuid())\n  tenantId    String\n  projectId   String\n  url         String\n  username    String\n  appPassword String    @db.Text // AES-256-GCM encrypted\n  status      String    @default(\"active\")\n  lastCheckAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  tenant  Tenant  @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  posts   Post[]\n\n  @@unique([tenantId, projectId, url])\n  @@index([tenantId])\n  @@index([projectId])\n}\n\n// ============================================================================\n// CONTENT GENERATION\n// ============================================================================\n\nmodel Post {\n  id               String   @id @default(uuid())\n  tenantId         String\n  projectId        String\n  wordPressSiteId  String?\n  title            String\n  content          String   @db.Text\n  excerpt          String   @db.Text\n  intro            String?  @db.Text\n  body             String?  @db.Text\n  conclusion       String?  @db.Text\n  featuredImageUrl String?\n  geoScore         Float?\n  authoritySignals Json? // Stored authority injection data\n  status           String   @default(\"draft\")\n  wordPressPostId  Int?\n  wordPressUrl     String?\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  tenant        Tenant         @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  project       Project        @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  wordPressSite WordPressSite? @relation(fields: [wordPressSiteId], references: [id], onDelete: SetNull)\n  embedding     PostEmbedding?\n  sources       Source[]\n  jobs          Job[]\n\n  @@index([tenantId])\n  @@index([projectId])\n  @@index([status])\n  @@index([wordPressSiteId])\n}\n\nmodel PostEmbedding {\n  id        String                       @id @default(uuid())\n  postId    String                       @unique\n  embedding Unsupported(\"vector(1536)\")?\n  createdAt DateTime                     @default(now())\n\n  post Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n\n  @@index([postId])\n}\n\nmodel Source {\n  id        String   @id @default(uuid())\n  postId    String\n  url       String\n  domain    String\n  title     String?\n  authority Float?\n  relevance Float?\n  createdAt DateTime @default(now())\n\n  post Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n\n  @@index([postId])\n  @@index([domain])\n}\n\n// ============================================================================\n// JOB QUEUE (Bull + Redis)\n// ============================================================================\n\nmodel Job {\n  id          String    @id @default(uuid())\n  tenantId    String\n  postId      String?\n  type        String // generate_post, validate_sources, publish_post, generate_image\n  status      String    @default(\"pending\") // pending, processing, completed, failed\n  attempts    Int       @default(0)\n  maxAttempts Int       @default(3)\n  priority    Int       @default(0)\n  progress    Float     @default(0)\n  result      Json?\n  error       String?\n  bullJobId   String?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  completedAt DateTime?\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  post   Post?  @relation(fields: [postId], references: [id], onDelete: SetNull)\n\n  @@index([tenantId])\n  @@index([postId])\n  @@index([status])\n  @@index([type])\n}\n\n// ============================================================================\n// PATTERNS & ANALYTICS\n// ============================================================================\n\nmodel PersonalPattern {\n  id                String   @id @default(uuid())\n  tenantId          String\n  patternType       String // bias, strength, recurring_mistake\n  description       String   @db.Text\n  frequency         Int      @default(1)\n  affectedDecisions Int      @default(0)\n  recommendation    String?  @db.Text\n  createdAt         DateTime @default(now())\n  updatedAt         DateTime @updatedAt\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId])\n  @@index([patternType])\n}\n\n// ============================================================================\n// SYSTEM\n// ============================================================================\n\nmodel SystemMetric {\n  id              String   @id @default(uuid())\n  timestamp       DateTime @default(now())\n  memoryUsageMb   Float\n  cpuUsagePercent Float\n  activeJobsCount Int\n  totalJobsDone   Int\n  averageJobTime  Float\n\n  @@index([timestamp])\n}\n",
